export function getSkillTree(cls: string): SkillTreeLayout | null {
  return ALL_SKILL_TREES[cls.toLowerCase()] ?? null;
}

// Find a node by matching skill name (case-insensitive)
export function findNodeBySkillName(layout: SkillTreeLayout, skillName: string): SkillTreeNode | null {
  const lower = skillName.toLowerCase().replace(/[^a-z0-9]/g, '');
  for (const n of layout.nodes) {
    if (!n.skillName) continue;
    const cmp = n.skillName.toLowerCase().replace(/[^a-z0-9]/g, '');
    if (cmp === lower || cmp.includes(lower) || lower.includes(cmp)) return n;
  }
  return null;
}
